import { motion } from 'framer-motion';
import { cn } from '../../utils';

type BodyZone = 'head' | 'chest' | 'gut' | 'upper' | 'lower' | 'core' | 'full' | null;

interface BodyGraphicProps {
  highlightZone?: BodyZone;
  className?: string;
  size?: number;
}

const zoneColors: Record<string, string> = {
  head:  '#EF4444',
  chest: '#F97316',
  gut:   '#EF4444',
  upper: '#F97316',
  lower: '#EF4444',
  core:  '#F97316',
  full:  '#EF4444',
};

export function BodyGraphic({ highlightZone, className, size = 160 }: BodyGraphicProps) {
  const color = highlightZone ? zoneColors[highlightZone] : 'transparent';
  const isHead    = highlightZone === 'head'  || highlightZone === 'full';
  const isChest   = highlightZone === 'chest' || highlightZone === 'upper' || highlightZone === 'full';
  const isGut     = highlightZone === 'gut'   || highlightZone === 'core'  || highlightZone === 'full';
  const isLower   = highlightZone === 'lower' || highlightZone === 'full';
  const isUpper   = highlightZone === 'upper' || highlightZone === 'full';

  const pulseAnim = {
    initial: { opacity: 0.6 },
    animate: { opacity: [0.6, 1, 0.6] },
    transition: { duration: 1.8, repeat: Infinity, ease: 'easeInOut' },
  };

  return (
    <div className={cn('flex items-center justify-center', className)}>
      <svg
        width={size}
        height={size * 1.7}
        viewBox="0 0 120 200"
        fill="none"
        xmlns="http://www.w3.org/2000/svg"
      >
        {/* Body silhouette base */}
        <ellipse cx="60" cy="30" rx="18" ry="20" fill="#D1E8E4" stroke="#2D9E8F" strokeWidth="1.5"/>
        <path d="M42 58 Q60 52 78 58 L82 120 Q60 128 38 120 Z" fill="#D1E8E4" stroke="#2D9E8F" strokeWidth="1.5"/>
        <path d="M42 60 L28 100 Q24 108 32 110 L40 90" fill="#D1E8E4" stroke="#2D9E8F" strokeWidth="1.5"/>
        <path d="M78 60 L92 100 Q96 108 88 110 L80 90" fill="#D1E8E4" stroke="#2D9E8F" strokeWidth="1.5"/>
        <path d="M46 120 L40 175 Q42 182 52 180 L56 140" fill="#D1E8E4" stroke="#2D9E8F" strokeWidth="1.5"/>
        <path d="M74 120 L80 175 Q78 182 68 180 L64 140" fill="#D1E8E4" stroke="#2D9E8F" strokeWidth="1.5"/>

        {/* HEAD highlight */}
        {isHead && (
          <motion.ellipse cx="60" cy="30" rx="18" ry="20" fill={color} fillOpacity="0.5"
            {...pulseAnim} />
        )}
        {/* CHEST / UPPER highlight */}
        {isChest && (
          <motion.path d="M44 58 Q60 52 76 58 L78 90 Q60 96 42 90 Z" fill={color} fillOpacity="0.45"
            {...pulseAnim} />
        )}
        {/* GUT / CORE highlight */}
        {isGut && (
          <motion.path d="M42 90 Q60 96 78 90 L80 118 Q60 126 40 118 Z" fill={color} fillOpacity="0.5"
            {...pulseAnim} />
        )}
        {/* UPPER BODY — shoulders + arms */}
        {isUpper && (
          <>
            <motion.path d="M42 60 L28 100 Q24 108 32 110 L40 90" fill={color} fillOpacity="0.4"
              {...pulseAnim} />
            <motion.path d="M78 60 L92 100 Q96 108 88 110 L80 90" fill={color} fillOpacity="0.4"
              {...pulseAnim} />
          </>
        )}
        {/* LOWER BODY highlight */}
        {isLower && (
          <>
            <motion.path d="M46 120 L40 175 Q42 182 52 180 L56 140" fill={color} fillOpacity="0.5"
              {...pulseAnim} />
            <motion.path d="M74 120 L80 175 Q78 182 68 180 L64 140" fill={color} fillOpacity="0.5"
              {...pulseAnim} />
          </>
        )}

        {/* Pulse ring on active zone */}
        {highlightZone && (
          <motion.circle
            cx="60"
            cy={isHead ? 30 : isGut || isLower ? 130 : 75}
            r="8"
            stroke={color}
            strokeWidth="2"
            fill="none"
            initial={{ scale: 0.5, opacity: 1 }}
            animate={{ scale: 2.5, opacity: 0 }}
            transition={{ duration: 1.5, repeat: Infinity, ease: 'easeOut' }}
          />
        )}

        {/* Spine line */}
        <line x1="60" y1="50" x2="60" y2="120" stroke="#2D9E8F" strokeWidth="0.8" strokeDasharray="3,3" opacity="0.4"/>
      </svg>
    </div>
  );
}

// ─── Nervous System Diagram ───────────────────────────────────────────────────
export function NervousSystemDiagram({ className }: { className?: string }) {
  const nodes = [
    { label: 'Sleep', x: 10,  y: 20,  angle: -140 },
    { label: 'Gut',   x: 12,  y: 55,  angle: -170 },
    { label: 'Mood',  x: 15,  y: 80,  angle: 170  },
    { label: 'Muscles', x: 75, y: 20, angle: -40  },
    { label: 'Hormones', x: 73, y: 60, angle: -10 },
  ];

  return (
    <div className={cn('relative', className)} style={{ height: 220 }}>
      <svg viewBox="0 0 300 220" className="w-full h-full">
        {/* Central nervous system */}
        <motion.ellipse cx="150" cy="110" rx="38" ry="52" fill="#0B4F4A" opacity="0.9"
          animate={{ opacity: [0.85, 1, 0.85] }}
          transition={{ duration: 3, repeat: Infinity, ease: 'easeInOut' }}
        />
        <text x="150" y="105" textAnchor="middle" fill="white" fontSize="9" fontWeight="600">Nervous</text>
        <text x="150" y="118" textAnchor="middle" fill="#5BBFB0" fontSize="9">System</text>

        {/* Animated connecting lines */}
        {[
          { x1:112, y1:80,  x2:35,  y2:38  },
          { x1:112, y1:110, x2:38,  y2:110 },
          { x1:112, y1:135, x2:40,  y2:165 },
          { x1:188, y1:80,  x2:260, y2:38  },
          { x1:188, y1:120, x2:258, y2:135 },
        ].map((line, i) => (
          <motion.line key={i} {...line} stroke="#2D9E8F" strokeWidth="1.5" strokeDasharray="4,3"
            initial={{ pathLength: 0, opacity: 0 }}
            animate={{ pathLength: 1, opacity: 0.7 }}
            transition={{ delay: i * 0.2 + 0.3, duration: 0.6 }}
          />
        ))}

        {/* Labels */}
        {[
          { label: 'Sleep',    x: 30,  y: 28,  color: '#F97316' },
          { label: 'Gut',      x: 30,  y: 108, color: '#EF4444' },
          { label: 'Mood',     x: 25,  y: 165, color: '#F97316' },
          { label: 'Muscles',  x: 258, y: 28,  color: '#EF4444' },
          { label: 'Hormones', x: 250, y: 135, color: '#F97316' },
        ].map((n, i) => (
          <motion.g key={n.label}
            initial={{ opacity: 0, scale: 0.7 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ delay: i * 0.15 + 0.5, duration: 0.4 }}
          >
            <circle cx={n.x} cy={n.y} r="16" fill={n.color} opacity="0.15"/>
            <text x={n.x} y={n.y + 4} textAnchor="middle" fill={n.color} fontSize="8.5" fontWeight="600">
              {n.label}
            </text>
          </motion.g>
        ))}
      </svg>
    </div>
  );
}

// ─── Breathing Orb ────────────────────────────────────────────────────────────
export function BreathingOrb({ className }: { className?: string }) {
  return (
    <div className={cn('flex items-center justify-center', className)}>
      <div className="relative">
        {[3, 2, 1].map((i) => (
          <motion.div
            key={i}
            className="absolute rounded-full border border-teal-300"
            style={{ inset: `-${i * 16}px` }}
            animate={{ scale: [1, 1.15, 1], opacity: [0.3, 0.1, 0.3] }}
            transition={{ duration: 4, repeat: Infinity, ease: 'easeInOut', delay: i * 0.3 }}
          />
        ))}
        <motion.div
          className="w-20 h-20 rounded-full bg-gradient-to-br from-teal-400 to-teal-700 flex items-center justify-center shadow-lg"
          animate={{ scale: [1, 1.12, 1] }}
          transition={{ duration: 4, repeat: Infinity, ease: 'easeInOut' }}
        >
          <span className="text-white text-2xl">🌬️</span>
        </motion.div>
      </div>
    </div>
  );
}
